module RefModule (
    input clk,
    input reset,
    input d,
    output reg q
);

    // Synchronous reset D flip-flop logic
      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            q <= 0;
        end else begin
            q <= d;
        end
    end

endmodule
